if (typeof window !== 'undefined') window.DISTRICT_CHEMOTHERAPY = DISTRICT_CHEMOTHERAPY;

// Animation registration — Flag waving on the central fortress turret
if (typeof window !== 'undefined' && window.PHARMA?.animations) {
  window.PHARMA.animations.register('chemotherapy', ({ THREE, scene, groupRoot, primitives, loop }) => {
    // Flag waving on the central fortress turret.
    const poleHeight = 18;
    const pole = new THREE.Mesh(
      new THREE.CylinderGeometry(0.15, 0.15, poleHeight, 8),
      new THREE.MeshLambertMaterial({ color: 0x712B13 })
    );
    pole.position.set(0, poleHeight / 2 + 8, 0);
    groupRoot.add(pole);
    const flag = new THREE.Mesh(
      new THREE.PlaneGeometry(4, 2, 8, 4),
      new THREE.MeshLambertMaterial({ color: 0xD85A30, side: THREE.DoubleSide })
    );
    flag.position.set(2, poleHeight + 7, 0);
    groupRoot.add(flag);
    const posAttr = flag.geometry.attributes.position;
    const baseX = new Float32Array(posAttr.count);
    const baseY = new Float32Array(posAttr.count);
    for (let i = 0; i < posAttr.count; i++) {
      baseX[i] = posAttr.getX(i);
      baseY[i] = posAttr.getY(i);
    }
    loop.add((_dt, t) => {
      for (let i = 0; i < posAttr.count; i++) {
        const x = baseX[i];
        // Wave amplitude grows with distance from the pole (left edge).
        const dx = (x + 2) / 4;
        const wave = Math.sin(t * 4 - x * 2) * 0.3 * dx;
        posAttr.setZ(i, wave);
      }
      posAttr.needsUpdate = true;
    });
  });
}
